namespace DocSummary.Models;

using System.ComponentModel.DataAnnotations;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
}

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    string Summarize(string documentText);
}

public class DocumentSummarizer : IDocumentSummarizer
{
    /// <summary>
    /// Produces a concise extractive summary by selecting the most important
    /// sentences from the document based on word-frequency scoring.
    /// </summary>
    public string Summarize(string documentText)
    {
        if (string.IsNullOrWhiteSpace(documentText))
            return string.Empty;

        var sentences = SplitIntoSentences(documentText);
        if (sentences.Count == 0)
            return string.Empty;

        if (sentences.Count <= 3)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scored = sentences
            .Select((s, i) => (Sentence: s, Index: i, Score: ScoreSentence(s, wordFrequencies)))
            .OrderByDescending(x => x.Score)
            .Take(Math.Max(1, sentences.Count / 3))
            .OrderBy(x => x.Index)
            .Select(x => x.Sentence);

        return string.Join(" ", scored);
    }

    private static List<string> SplitIntoSentences(string text)
    {
        return text
            .Split(['.', '!', '?'], StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .Where(s => s.Length > 0)
            .Select(s => s + ".")
            .ToList();
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in GetWords(sentence))
            {
                freq.TryGetValue(word, out var count);
                freq[word] = count + 1;
            }
        }
        return freq;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
    {
        var words = GetWords(sentence);
        if (words.Length == 0)
            return 0;

        double total = words.Sum(w => wordFrequencies.GetValueOrDefault(w, 0));
        return total / words.Length;
    }

    private static string[] GetWords(string text) =>
        text.Split([' ', ',', ';', ':', '"', '\'', '(', ')', '[', ']', '\n', '\r', '\t'],
            StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
}

namespace DocSummary.Controllers;

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController(IDocumentSummarizer summarizer) : ControllerBase
{
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = summarizer.Summarize(request.DocumentText);
        return Ok(new SummarizeResponse { Summary = summary });
    }
}

